                    topic = payload.get("topic")
                    if topic:
                        await self.connection_manager.subscribe(agent_id, topic)
                        await websocket.send_json(
                            {"type": "subscription_confirmed", "topic": topic, "timestamp": datetime.now(UTC).isoformat()}
                        )
